insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.i-m-a-roswell-ga-family-photographer-spe','I’m a Roswell, GA family photographer specializing in newborn, family, maternity, milestone, and couples photography. I’m drawn to the beauty in everyday moments — soft light, genuine connection, and the small details that make each season of life meaningful.','I’m a Roswell, GA family photographer specializing in new…','about','Page','textarea',40) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.as-a-mom-myself-i-understand-how-fleetin','As a mom myself, I understand how fleeting these moments are and how quickly life changes. That perspective shapes the way I approach every session. My goal is to create a relaxed, comfortable experience where your family can slow down, be present, and simply enjoy time together.','As a mom myself, I understand how fleeting these moments …','about','Page','textarea',41) on conflict (key) do nothing;
