insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.i-take-the-time-to-connect-with-your-chi','I take the time to connect with your children, meet them where they are, and help them feel safe and confident in front of the camera. Whether your child is shy and needs a few minutes to warm up or full of energy and ready to explore, I embrace it all.','I take the time to connect with your children, meet them …','experience','Page','textarea',64) on conflict (key) do nothing;
